import React, { useState } from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';

export default function Sidebar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const isStaff = user?.userType === 'user';
  const [hoverLogout, setHoverLogout] = useState(false);

  const navItems = [
    { path:'/dashboard',        icon:'▣',  label:'Dashboard',       show:true },
    { path:'/books',            icon:'📚', label:'Books',            show:true },
    { path:'/members',          icon:'👥', label:'Members',          show:isStaff },
    { path:'/requests',         icon:'🔔', label:'Borrow Requests',  show:isStaff },
    { path:'/borrows',          icon:'↔',  label:'Borrows',          show:isStaff },
    { path:'/categories',       icon:'◈',  label:'Categories',       show:true },
    { path:'/create-assistant', icon:'➕', label:'Add Assistant',    show:user?.role==='librarian' },
    { path:'/my-borrows',       icon:'📋', label:'My Library',       show:!isStaff },
  ];

  const roleLabel: any = { librarian:'Librarian', library_assistant:'Library Assistant', student:'Student', staff:'Staff Member' };
  const roleColor: any = { librarian:'#c9a84c', library_assistant:'#10b981', student:'#3b82f6', staff:'#8b5cf6' };
  const rc = roleColor[user?.role || ''] || '#c9a84c';

  return (
    <aside style={{ width:248, minHeight:'100vh', background:'#0d0d1c', borderRight:'1px solid rgba(255,255,255,0.06)', display:'flex', flexDirection:'column', flexShrink:0 }}>
      {/* Logo */}
      <div style={{ padding:'26px 22px 22px', borderBottom:'1px solid rgba(255,255,255,0.06)' }}>
        <div style={{ display:'flex', alignItems:'center', gap:12 }}>
          <div style={{ width:40, height:40, background:'linear-gradient(135deg,#c9a84c,#b8962f)', borderRadius:11, display:'flex', alignItems:'center', justifyContent:'center', fontSize:19, boxShadow:'0 4px 12px rgba(201,168,76,0.3)' }}>📖</div>
          <div>
            <div style={{ fontFamily:"'Playfair Display',serif", fontSize:18, fontWeight:700, color:'#fff', lineHeight:1.2 }}>LibraryMS</div>
            <div style={{ fontSize:10, color:'rgba(201,168,76,0.7)', letterSpacing:'1px', textTransform:'uppercase', marginTop:2 }}>BAUST</div>
          </div>
        </div>
      </div>

      {/* Nav */}
      <nav style={{ flex:1, padding:'14px 12px', overflowY:'auto' }}>
        <div style={{ fontSize:10, fontWeight:700, color:'rgba(255,255,255,0.2)', letterSpacing:'1.5px', textTransform:'uppercase', padding:'6px 10px', marginBottom:6 }}>
          Navigation
        </div>
        {navItems.filter(i=>i.show).map(item=>(
          <NavLink key={item.path} to={item.path}
            style={({ isActive })=>({
              display:'flex', alignItems:'center', gap:11,
              padding:'11px 14px', borderRadius:11,
              fontSize:14, fontWeight: isActive ? 600 : 500,
              color: isActive ? '#1a1a2e' : 'rgba(255,255,255,0.5)',
              background: isActive ? '#c9a84c' : 'transparent',
              cursor:'pointer', textDecoration:'none',
              marginBottom:3, transition:'all .18s',
              boxShadow: isActive ? '0 4px 14px rgba(201,168,76,0.3)' : 'none',
            })}
            onMouseEnter={(e:any)=>{ if(!e.currentTarget.classList.contains('active')){ e.currentTarget.style.background='rgba(255,255,255,0.06)'; e.currentTarget.style.color='rgba(255,255,255,0.85)'; } }}
            onMouseLeave={(e:any)=>{ const isActive=e.currentTarget.style.background==='rgb(201, 168, 76)'; if(!isActive){ e.currentTarget.style.background='transparent'; e.currentTarget.style.color='rgba(255,255,255,0.5)'; } }}
          >
            <span style={{ fontSize:16, width:22, textAlign:'center', flexShrink:0 }}>{item.icon}</span>
            <span>{item.label}</span>
          </NavLink>
        ))}
      </nav>

      {/* User */}
      <div style={{ padding:'14px 12px 18px', borderTop:'1px solid rgba(255,255,255,0.06)' }}>
        <div style={{ background:'rgba(255,255,255,0.04)', border:'1px solid rgba(255,255,255,0.07)', borderRadius:13, padding:'14px 14px 10px', marginBottom:8 }}>
          <div style={{ display:'flex', alignItems:'center', gap:11, marginBottom:10 }}>
            <div style={{ width:38, height:38, background:`linear-gradient(135deg, ${rc}, ${rc}99)`, borderRadius:'50%', display:'flex', alignItems:'center', justifyContent:'center', fontWeight:700, color:'#1a1a2e', fontSize:16, flexShrink:0, boxShadow:`0 3px 10px ${rc}44` }}>
              {user?.name?.charAt(0).toUpperCase()}
            </div>
            <div style={{ minWidth:0 }}>
              <div style={{ fontSize:14, fontWeight:700, color:'#fff', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{user?.name}</div>
              <div style={{ fontSize:11, color:rc, marginTop:1 }}>{roleLabel[user?.role||''] || user?.role}</div>
            </div>
          </div>
          {user?.member_id && (
            <div style={{ fontSize:11, color:'rgba(255,255,255,0.3)', fontFamily:'monospace', background:'rgba(0,0,0,0.2)', padding:'4px 8px', borderRadius:6, display:'inline-block' }}>
              ID: {user.member_id}
            </div>
          )}
        </div>
        <button
          onMouseEnter={()=>setHoverLogout(true)}
          onMouseLeave={()=>setHoverLogout(false)}
          onClick={()=>{ logout(); navigate('/login'); }}
          style={{ width:'100%', display:'flex', alignItems:'center', justifyContent:'center', gap:8, padding:'10px', borderRadius:10, fontSize:13, fontWeight:600, color: hoverLogout ? '#ef4444' : 'rgba(255,255,255,0.35)', background: hoverLogout ? 'rgba(239,68,68,0.1)' : 'transparent', border: hoverLogout ? '1px solid rgba(239,68,68,0.25)' : '1px solid transparent', cursor:'pointer', fontFamily:'inherit', transition:'all .2s' }}>
          ⎋ Sign Out
        </button>
      </div>
    </aside>
  );
}
